Exit fullscreen mode

सही तरीका (The Fixed Code):

इस error को ठीक करने के लिए, हमें Dependency Array का सही ढंग से उपयोग करना होगा, या फिर Functional Update का सहारा लेना होगा।

import React, { useState, useEffect } from 'react';
function GoodCounter() {
const [count, setCount] = useState(0);
useEffect(() => {
// dependency array में खाली array [] देने से यह सिर्फ mount पर चलेगा
setCount(prevCount => prevCount + 1);
}, []);
return (
<div>
<p>Count: {count}</p>
</div>
);
}
export default GoodCounter;

