Common Mistakes 3: Cleanups को भूल जाना (Memory Leaks)

जब भी आप किसी बाह्य API, सॉकेट (WebSockets), या इवेंट लिसनर्स को useEffect\ में जोड़ते हैं, तो घटक के नष्ट (unmount) होने पर उन्हें हटाना बहुत आवश्यक है। अन्यथा, बैकग्राउंड में कोड चलता रहेगा और यह आपकी एप्लीकेशन को धीमा कर देगा।

गलत तरीका (The Broken Code):

import React, { useState, useEffect } from 'react';
function BadEventListener() {
const [windowWidth, setWindowWidth] = useState(window.innerWidth);
useEffect(() => {
// यहाँ इवेंट लिसनर तो जोड़ दिया गया, लेकिन अनमाउंट होने पर हटाया नहीं गया
window.addEventListener('resize', () => {
setWindowWidth(window.innerWidth);
});
}, []);
return <p>Window Width: {windowWidth}px</p>;
}
export default BadEventListener;

Enter fullscreen mode

Exit fullscreen mode

सही तरीका (The Fixed Code):

import React, { useState, useEffect } from 'react';
function GoodEventListener() {
const [windowWidth, setWindowWidth] = useState(window.innerWidth);
useEffect(() => {
const handleResize = () => {
setWindowWidth(window.innerWidth);
};
window.addEventListener('resize', handleResize);
// क्लीनअप फ़ंक्शन का उपयोग करके इवेंट लिसनर को हटाया गया
return () => {
window.removeEventListener('resize', handleResize);
};
}, []);
return <p>Window Width: {windowWidth}px</p>;
}
export default GoodEventListener;

