Step-by-Step Guide: Custom Hook कैसे बनाएं?

यदि आप अपने कोड को साफ और रियूजेबल बनाना चाहते हैं, तो Custom Hooks आपके सबसे अच्छे दोस्त हैं। चलिए, एक कस्टम हुक useFetch बनाते हैं जो किसी भी API से डेटा सुरक्षित रूप से लाने का काम करेगा और लोडिंग एवं एरर स्टेट्स को भी संभालेगा।

स्टेप 1: फ़ाइल बनाएँ

सबसे पहले अपने प्रोजेक्ट में useFetch.js नाम की एक नई फ़ाइल बनाएँ।

स्टेप 2: कस्टम हुक का लॉजिक लिखें

हम यहाँ Fetch API के साथ AbortController का इस्तेमाल करेंगे ताकि कंपोनेंट अनमाउंट होने पर नेटवर्क रिक्वेस्ट कैंसिल हो सके।

import { useState, useEffect } from 'react';
function useFetch(url) {
const [data, setData] = useState(null);
const [loading, setLoading] = useState(true);
const [error, setError] = useState(null);
useEffect(() => {
const abortController = new AbortController();
const fetchData = async () => {
try {
setLoading(true);
const response = await fetch(url, { signal: abortController.signal });
if (!response.ok) {
throw new Error('Network response was not ok');
}
const result = await response.json();
setData(result);
setError(null);
} catch (err) {
if (err.name !== 'AbortError') {
setError(err.message);
}
} finally {
setLoading(false);
}
};
fetchData();
// cleanup function to abort fetch request
return () => {
abortController.abort();
};
}, [url]);
return { data, loading, error };
}
export default useFetch;

